int main(){int n;scanf("%d",&n);vector<long long>a(n);for(auto&x:a)scanf("%lld",&x);sort(a.begin(),a.end());int m;scanf("%d",&m);string out;while(m--){long long x;scanf("%lld",&x);out+=binary_search(a.begin(),a.end(),x)?"1\n":"0\n";}fputs(out.c_str(),stdout);}
